function withTheme(node: ReactNode): ReactNode {
  return createElement(ThemeProvider, null, node)
}

export async function render(
  node: ReactNode,
  options?: NodeJS.WriteStream | RenderOptions,
): Promise<Instance> {
  return inkRender(withTheme(node), options)
}

export default function useInput(
  handler: (input: string, key: Key) => void,
  options?: UseInputOptions,
) {
  const app = useApp()
  useEffect(() => {
    app.on('input', handler)
    return () => {
      app.off('input', handler)
    }
  }, [app, handler])
}

export default function Button({
  children,
  onPress,
  disabled = false,
  ...props
}: ButtonProps) {
  const theme = useTheme()
  const [isFocused, setIsFocused] = useState(false)

  return (
    <BaseBox
      {...props}
      onFocus={() => setIsFocused(true)}
      onBlur={() => setIsFocused(false)}
    >
      <Text color={disabled ? theme.colors.gray : theme.colors.blue}>
        {children}
      </Text>
    </BaseBox>
  )
}

export class ScreenRouter {
  private stack: Screen[] = []

  push(screen: Screen) {
    this.stack.push(screen)
    this.renderCurrent()
  }

  pop() {
    if (this.stack.length > 1) {
      this.stack.pop()
      this.renderCurrent()
    }
  }

  private renderCurrent() {
    const current = this.stack[this.stack.length - 1]
    inkRender(current.component)
  }
}

export function rgbToAnsi(r: number, g: number, b: number): string {
  if (supportsTrueColor) {
    return `\x1b[38;2;${r};${g};${b}m`
  } else {
    // 降级到 256 色
    const ansi256 = rgbToAnsi256(r, g, b)
    return `\x1b[38;5;${ansi256}m`
  }
}

